import { createSignal, onMount } from 'solid-js';
import { Button, Typography } from '@mui/material';

function AdminDashboard() {
  const [count, setCount] = createSignal(0);

  onMount(() => {
    // Initialize the dashboard data here
    setCount(10);
  });

  return (
    <div>
      <Typography variant="h1">Admin Dashboard</Typography>
      <Button variant="contained" onClick={() => setCount(count() + 1)}>Increment Count</Button>
      <p>Count: {count()}</p>
    </div>
  );
}

export default AdminDashboard;
```
This code creates a basic admin dashboard with a button that increments a count when clicked.

**Step 4: Create a new route for the admin dashboard**

Create a new file `routes.solid` and add the following code to create a new route for the admin dashboard:
```solid
import { createRoute } from 'solid-js/router';

createRoute('/admin', () => AdminDashboard());
```
This code creates a new route for the admin dashboard at the `/admin` path.

**Step 5: Start the development server**

Start the development server by running the following command:
```bash
npm start
```
This will start the SolidJS development server, and you can access the admin dashboard at `http://localhost:3000/admin`.

